%% --- shared_logic: tools (generated from compile_logic) ---

%% Check if a tool name is in the destructive set (bash, write, edit).
is_destructive(Tool_name, Result) :-
    Result = memberchk(Tool_name, ["bash", "write", "edit"]).

%% Check if a tool is read-only (safe without approval).
is_safe(Tool_name, Result) :-
    (Tool_name == "Read" -> Result = true ; Result = false).

%% Check if a tool is in the user-approved set.
is_approved(Tool_name, Approved_set, Result) :-
    Result = memberchk(Tool_name, Approved_set).

%% Check if a tool requires user approval (destructive and not safe).
tool_needs_approval(Tool_name, Result) :-
    (Tool_name == "Read" ->
        Result = false
    ;
    Result = memberchk(Tool_name, ["bash", "write", "edit"])
    ).

%% Return true if tool should be blocked: destructive + not in approved set.
check_approval_block(Tool_name, Approved_set, Result) :-
    (\+ memberchk(Tool_name, ["bash", "write", "edit"]) ->
        Result = false
    ;
    (\+ memberchk(Tool_name, Approved_set) -> Result = true ; Result = false)
    ).

%% Check if tool name has mcp: prefix indicating MCP dispatch.
is_mcp_tool(Tool_name, Result) :-
    (atom_concat('mcp:', _, Tool_name) -> Result = true ; Result = false).

%% Check that all required parameter keys exist in args dict.
has_required_params(Args, Required_keys, Result) :-
    Result = forall(member(K, Required_keys), get_dict(K, Args, _)).

%% Categorize a tool as destructive, safe, or normal.
tool_category(Tool_name, Result) :-
    (memberchk(Tool_name, ["bash", "write", "edit"]) ->
        Result = "destructive"
    ;
    (Tool_name == "Read" ->
        Result = "safe"
    ;
    Result = "normal"
    )
    ).

%% Check if a tool name refers to a built-in (non-MCP) tool.
is_builtin(Tool_name, Result) :-
    (\+ atom_concat('mcp__', _, Tool_name) -> Result = true ; Result = false).

%% Check if a tool requires file path validation (read, write, or edit).
needs_path_validation(Tool_name, Result) :-
    ((atom_concat('read', _, Tool_name) ; (atom_concat('write', _, Tool_name) ; atom_concat('edit', _, Tool_name))) -> Result = true ; Result = false).

%% Return the number of arguments a tool accepts. Returns 0 if tool not found.
arg_count(State, _Tool_name, Result) :-
    length(State.args, Result).

%% Check if a tool has a JSON schema definition for its parameters.
has_schema(State, _Tool_name, Result) :-
    length(State.schema, Result) > 0.

%% Check if a tool name is non-empty.
name_is_valid(Tool_name, Result) :-
    length(Tool_name, Result) > 0.

%% Execute a tool by name
execute_tool(ToolName, Params, Result) :-
    (tool_handler(ToolName, _) ->
        execute_tool_impl(ToolName, Params, Result)
    ; execute_plugin_tool(ToolName, Params, Result) ->
        true
    ; format(atom(Err), "Unknown tool: ~w", [ToolName]),
      Result = error(Err)
    ).

%% Plugin tool execution — loads from ~/.agent-loop/plugins/
:- dynamic plugin_tool/3.  %% plugin_tool(Name, Template, Params)

load_plugins :-
    retractall(plugin_tool(_, _, _)),
    (getenv('HOME', Home) -> true ; Home = "."),
    format(atom(PluginDir), "~w/.agent-loop/plugins", [Home]),
    (exists_directory(PluginDir) ->
        directory_files(PluginDir, Files),
        include([F]>>(atom_concat(_, '.json', F)), Files, JsonFiles),
        maplist([JF]>>(
            format(atom(FullPath), "~w/~w", [PluginDir, JF]),
            catch(load_plugin_file(FullPath), _, true)
        ), JsonFiles)
    ; true).

load_plugin_file(Path) :-
    read_file_to_string(Path, Content, []),
    atom_json_dict(Content, Manifest, []),
    (get_dict(tools, Manifest, Tools) ->
        maplist([Tool]>>(
            get_dict(name, Tool, Name),
            (get_dict(command_template, Tool, Template) -> true ; Template = ""),
            (get_dict(parameters, Tool, Params) -> true ; Params = []),
            atom_string(NameAtom, Name),
            assertz(plugin_tool(NameAtom, Template, Params))
        ), Tools)
    ; true).

execute_plugin_tool(ToolName, Params, Result) :-
    plugin_tool(ToolName, Template, PluginParams),
    render_plugin_template(Template, Params, PluginParams, Command),
    execute_tool_impl(bash, _{command: Command}, Result).

render_plugin_template(Template, Args, PluginParams, Rendered) :-
    atom_string(Template, TStr),
    foldl([P, In, Out]>>(
        (is_dict(P) -> get_dict(name, P, PName0) ; PName0 = P),
        (atom(PName0) -> PNameAtom = PName0 ; atom_string(PNameAtom, PName0)),
        atom_string(PNameAtom, PNameStr),
        format(string(Placeholder), "{~w}", [PNameStr]),
        (get_dict(PNameAtom, Args, Val) ->
            term_string(Val, ValStr),
            replace_all_in_string(In, Placeholder, ValStr, Out)
        ; Out = In)
    ), PluginParams, TStr, RenderedStr),
    atom_string(Rendered, RenderedStr).

%% replace_all_in_string(+Input, +Search, +Replace, -Output)
replace_all_in_string(Input, Search, Replace, Output) :-
    string_length(Search, SLen),
    (SLen =:= 0 -> Output = Input
    ; replace_all_helper(Input, Search, SLen, Replace, Output)).
replace_all_helper(Input, Search, SLen, Replace, Output) :-
    (sub_string(Input, Before, SLen, _, Search) ->
        sub_string(Input, 0, Before, _, Left),
        AfterPos is Before + SLen,
        sub_string(Input, AfterPos, _, 0, Right),
        replace_all_helper(Right, Search, SLen, Replace, RestOutput),
        string_concat(Left, Replace, Tmp),
        string_concat(Tmp, RestOutput, Output)
    ; Output = Input).

atomics_to_string([], _, "").
atomics_to_string([Part], _, Part).
atomics_to_string([Part|Rest], Sep, Result) :-
    Rest \= [],
    atomics_to_string(Rest, Sep, RestStr),
    string_concat(Part, Sep, WithSep),
    string_concat(WithSep, RestStr, Result).

execute_tool_impl(bash, Params, Result) :-
    get_dict(command, Params, Cmd),
    check_command_allowed(Cmd, CmdCheck),
    (CmdCheck = blocked(Reason) ->
        format(atom(BlkErr), "Blocked: ~w", [Reason]),
        Result = error(BlkErr)
    ;
        tool_spec(bash, BashProps),
        (member(timeout(Timeout), BashProps) -> true ; Timeout = 120),
        catch(
            call_with_time_limit(Timeout, (
                setup_call_cleanup(
                    process_create(path(bash), ['-c', Cmd],
                        [stdout(pipe(Out)), stderr(pipe(Err)), process(PID)]),
                    (read_string(Out, _, StdOut),
                     read_string(Err, _, StdErr),
                     process_wait(PID, Status)),
                    (close(Out), close(Err))),
                (Status = exit(0) ->
                    Result0 = ok(StdOut)
                ;   format(atom(ErrMsg), "Exit ~w: ~w~w", [Status, StdOut, StdErr]),
                    Result0 = error(ErrMsg))
            )),
            time_limit_exceeded,
            (format(atom(TimeErr), "Command timed out after ~w seconds", [Timeout]),
             Result0 = error(TimeErr))
        ),
        Result = Result0
    ).

execute_tool_impl(read, Params, Result) :-
    get_dict(path, Params, FilePath),
    check_path_allowed(FilePath, PathCheck),
    (PathCheck = blocked(Reason) ->
        format(atom(BlkErr), "Blocked: ~w", [Reason]),
        Result = error(BlkErr)
    ; exists_file(FilePath) ->
        read_file_to_string(FilePath, Content, []),
        Result = ok(Content)
    ;   format(atom(Err), "File not found: ~w", [FilePath]),
        Result = error(Err)).

execute_tool_impl(write, Params, Result) :-
    get_dict(path, Params, FilePath),
    get_dict(content, Params, Content),
    check_path_allowed(FilePath, PathCheck),
    (PathCheck = blocked(Reason) ->
        format(atom(BlkErr), "Blocked: ~w", [Reason]),
        Result = error(BlkErr)
    ;
        setup_call_cleanup(
            open(FilePath, write, Out),
            write(Out, Content),
            close(Out)),
        format(atom(Msg), "Wrote ~w", [FilePath]),
        Result = ok(Msg)
    ).

execute_tool_impl(edit, Params, Result) :-
    get_dict(path, Params, FilePath),
    get_dict(old_string, Params, OldStr),
    get_dict(new_string, Params, NewStr),
    check_path_allowed(FilePath, PathCheck),
    (PathCheck = blocked(Reason) ->
        format(atom(BlkErr), "Blocked: ~w", [Reason]),
        Result = error(BlkErr)
    ; exists_file(FilePath) ->
        read_file_to_string(FilePath, Content, []),
        (sub_string(Content, Before, _, After, OldStr) ->
            sub_string(Content, 0, Before, _, Pre),
            Len is Before + (string_length(Content) - Before - After),
            sub_string(Content, Len, After, 0, Post),
            string_concat(Pre, NewStr, Temp),
            string_concat(Temp, Post, NewContent),
            setup_call_cleanup(
                open(FilePath, write, Out),
                write(Out, NewContent),
                close(Out)),
            Result = ok("Edit applied")
        ;   Result = error("Old string not found"))
    ;   format(atom(Err), "File not found: ~w", [FilePath]),
        Result = error(Err)).

%% Build JSON Schema input_schema from tool_spec parameters
build_tool_input_schema(ToolName, Schema) :-
    tool_spec(ToolName, Props),
    member(parameters(Params), Props),
    build_properties(Params, PropsDict),
    build_required(Params, ReqList),
    Schema = _{type: "object", properties: PropsDict, required: ReqList}.

build_properties([], _{}).
build_properties([param(Name, Type, _, Desc)|Rest], Props) :-
    build_properties(Rest, RestProps),
    put_dict(Name, RestProps, _{type: Type, description: Desc}, Props).

build_required([], []).
build_required([param(Name, _, required, _)|Rest], [Name|RR]) :-
    build_required(Rest, RR).
build_required([param(_, _, O, _)|Rest], RR) :-
    O \= required, build_required(Rest, RR).

%% Describe a tool call for display
describe_tool_call(Backend, ToolName, Params, Desc) :-
    (tool_description(Backend, ToolName, Verb, ParamKey, Mode) ->
        (get_dict(ParamKey, Params, Val0) -> true ; Val0 = "?"),
        format_tool_value(Mode, Val0, Val),
        format(atom(Desc), "~w ~w", [Verb, Val])
    ; atom_string(ToolName, Desc)).

format_tool_value(basename, Path, Base) :-
    file_base_name(Path, Base).
format_tool_value(raw, Val, Val).
format_tool_value(truncate(Max), Val, Truncated) :-
    string_length(Val, Len),
    (Len > Max ->
        Cut is Max - 3,
        sub_string(Val, 0, Cut, _, Pre),
        string_concat(Pre, "...", Truncated)
    ; Truncated = Val).

%% Confirm before executing destructive tools
confirm_destructive(ToolName, Approved) :-
    (destructive_tool(ToolName) ->
        format("Tool '~w' may modify files. Execute? [y/N] ", [ToolName]),
        read_line_to_string(user_input, Response),
        (member(Response, ["y", "Y", "yes"]) -> Approved = true ; Approved = false)
    ; Approved = true).
